import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { getAllStocks } from "../services/stockService";

export default function Portfolio() {
  const [portfolio, setPortfolio] = useState([]);
  const [stocks, setStocks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Load portfolio from localStorage
    const savedPortfolio = localStorage.getItem("portfolio");
    if (savedPortfolio) {
      setPortfolio(JSON.parse(savedPortfolio));
    }
    
    fetchStocks();
  }, []);

  const fetchStocks = async () => {
    try {
      const allStocks = await getAllStocks();
      setStocks(allStocks);
    } catch (error) {
      console.error("Error fetching stocks:", error);
    } finally {
      setLoading(false);
    }
  };

  // Calculate portfolio metrics
  const portfolioWithDetails = portfolio.map(item => {
    const stock = stocks.find(s => s.symbol === item.symbol);
    if (!stock) return null;
    
    const currentValue = stock.price * item.quantity;
    const investedValue = item.avgPrice * item.quantity;
    const pnl = currentValue - investedValue;
    const pnlPercent = (pnl / investedValue) * 100;
    
    return {
      ...item,
      stock,
      currentValue,
      investedValue,
      pnl,
      pnlPercent
    };
  }).filter(Boolean);

  const totalInvested = portfolioWithDetails.reduce((sum, item) => sum + item.investedValue, 0);
  const totalCurrent = portfolioWithDetails.reduce((sum, item) => sum + item.currentValue, 0);
  const totalPnL = totalCurrent - totalInvested;
  const totalPnLPercent = totalInvested > 0 ? (totalPnL / totalInvested) * 100 : 0;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading your portfolio...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <h1 className="text-3xl font-bold text-gray-800 mb-6">My Portfolio</h1>

        {portfolio.length > 0 ? (
          <>
            {/* Portfolio Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
              <div className="bg-white rounded-lg shadow-md p-6">
                <p className="text-sm text-gray-600 mb-1">Total Investment</p>
                <p className="text-2xl font-bold text-gray-800">
                  ₹{totalInvested.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow-md p-6">
                <p className="text-sm text-gray-600 mb-1">Current Value</p>
                <p className="text-2xl font-bold text-gray-800">
                  ₹{totalCurrent.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow-md p-6">
                <p className="text-sm text-gray-600 mb-1">Total P&L</p>
                <p className={`text-2xl font-bold ${totalPnL >= 0 ? "text-green-600" : "text-red-600"}`}>
                  {totalPnL >= 0 ? "+" : ""}₹{totalPnL.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow-md p-6">
                <p className="text-sm text-gray-600 mb-1">Returns</p>
                <p className={`text-2xl font-bold ${totalPnLPercent >= 0 ? "text-green-600" : "text-red-600"}`}>
                  {totalPnLPercent >= 0 ? "+" : ""}{totalPnLPercent.toFixed(2)}%
                </p>
              </div>
            </div>

            {/* Holdings Table */}
            <div className="bg-white rounded-lg shadow-md overflow-hidden">
              <div className="p-6 border-b border-gray-200">
                <h2 className="text-xl font-bold text-gray-800">Your Holdings</h2>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stock</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Qty</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Avg Price</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">LTP</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Invested</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Current Value</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">P&L</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">% Change</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {portfolioWithDetails.map((item) => (
                      <tr key={item.symbol} className="hover:bg-gray-50">
                        <td className="px-6 py-4">
                          <Link to={`/stock/${item.symbol}`} className="hover:text-indigo-600">
                            <p className="font-semibold text-gray-800">{item.symbol}</p>
                            <p className="text-sm text-gray-600">{item.stock.name}</p>
                          </Link>
                        </td>
                        <td className="px-6 py-4 text-right font-medium text-gray-800">
                          {item.quantity}
                        </td>
                        <td className="px-6 py-4 text-right text-gray-600">
                          ₹{item.avgPrice.toFixed(2)}
                        </td>
                        <td className="px-6 py-4 text-right font-medium text-gray-800">
                          ₹{item.stock.price.toLocaleString('en-IN')}
                        </td>
                        <td className="px-6 py-4 text-right text-gray-600">
                          ₹{item.investedValue.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                        </td>
                        <td className="px-6 py-4 text-right font-medium text-gray-800">
                          ₹{item.currentValue.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                        </td>
                        <td className={`px-6 py-4 text-right font-medium ${item.pnl >= 0 ? "text-green-600" : "text-red-600"}`}>
                          {item.pnl >= 0 ? "+" : ""}₹{item.pnl.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                        </td>
                        <td className={`px-6 py-4 text-right font-medium ${item.pnlPercent >= 0 ? "text-green-600" : "text-red-600"}`}>
                          {item.pnlPercent >= 0 ? "+" : ""}{item.pnlPercent.toFixed(2)}%
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Quick Actions */}
            <div className="mt-6 flex gap-4">
              <Link
                to="/markets"
                className="inline-block bg-indigo-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200"
              >
                Add More Stocks
              </Link>
              <button
                onClick={() => {
                  // Demo: Add sample portfolio data
                  const samplePortfolio = [
                    { symbol: "RELIANCE", quantity: 10, avgPrice: 2400 },
                    { symbol: "TCS", quantity: 5, avgPrice: 3500 },
                    { symbol: "INFY", quantity: 20, avgPrice: 1400 }
                  ];
                  localStorage.setItem("portfolio", JSON.stringify(samplePortfolio));
                  window.location.reload();
                }}
                className="inline-block bg-gray-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-gray-700 transition-colors duration-200"
              >
                Load Demo Portfolio
              </button>
            </div>
          </>
        ) : (
          <div className="text-center py-16">
            <div className="mb-6">
              <svg className="w-24 h-24 mx-auto text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-4">Your portfolio is empty</h2>
            <p className="text-gray-600 mb-6 max-w-md mx-auto">
              Start building your investment portfolio by adding stocks. 
              Track your investments and monitor your returns in real-time.
            </p>
            <div className="flex gap-4 justify-center">
              <Link
                to="/markets"
                className="inline-block bg-indigo-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200"
              >
                Start Investing
              </Link>
              <button
                onClick={() => {
                  const samplePortfolio = [
                    { symbol: "RELIANCE", quantity: 10, avgPrice: 2400 },
                    { symbol: "TCS", quantity: 5, avgPrice: 3500 },
                    { symbol: "INFY", quantity: 20, avgPrice: 1400 }
                  ];
                  localStorage.setItem("portfolio", JSON.stringify(samplePortfolio));
                  window.location.reload();
                }}
                className="inline-block bg-gray-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-gray-700 transition-colors duration-200"
              >
                Load Demo Data
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
